import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { NavigationProvider } from './context/NavigationContext';
import Navbar from './components/Navbar';
import Notifications from './components/Notifications';
import Loading from './components/Loading';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import GameDetail from './pages/GameDetail';
import Cart from './pages/Cart';
import Profile from './pages/Profile';
import Favorites from './pages/Favorites';
import GoogleCallback from './pages/GoogleCallback';
import TestBackend from './pages/TestBackend';

const AdminDashboard = () => {
  const { state } = useAuth();

  if (!state.isAuthenticated || state.user?.role !== 'admin') {
    return (
      <div style={{ minHeight: '100vh', backgroundColor: '#111827', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <div style={{ textAlign: 'center' }}>
          <h1 style={{ fontSize: '2.5rem', fontWeight: 'bold', marginBottom: '1rem' }}>غير مصرح بالوصول</h1>
          <p style={{ fontSize: '1.25rem', marginBottom: '2rem' }}>يجب تسجيل الدخول كمدير للوصول إلى هذه الصفحة</p>
          <Navigate to="/login" replace />
        </div>
      </div>
    );
  }

  return (
    <div style={{ minHeight: '100vh', backgroundColor: '#111827', color: 'white', padding: '1.5rem' }}>
      <div style={{ maxWidth: '1280px', margin: '0 auto' }}>
        <div style={{ marginBottom: '2rem' }}>
          <h1 style={{ fontSize: '2.5rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>لوحة تحكم الإدمن</h1>
          <p style={{ color: '#9CA3AF' }}>مرحباً Admin</p>
        </div>

        <div style={{ backgroundColor: '#1F2937', padding: '2rem', borderRadius: '0.5rem' }}>
          <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '1rem' }}>مرحباً في لوحة التحكم</h2>
          <p style={{ color: '#9CA3AF', marginBottom: '2rem' }}>هذه لوحة تحكم الإدمن البسيطة</p>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1rem' }}>
            <div style={{ backgroundColor: '#374151', padding: '1.5rem', borderRadius: '0.5rem', textAlign: 'center' }}>
              <h3 style={{ fontSize: '1.125rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>إدارة الألعاب</h3>
              <p style={{ color: '#9CA3AF', fontSize: '0.875rem' }}>إدارة وتعديل الألعاب المتوفرة</p>
            </div>

            <div style={{ backgroundColor: '#374151', padding: '1.5rem', borderRadius: '0.5rem', textAlign: 'center' }}>
              <h3 style={{ fontSize: '1.125rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>إدارة المستخدمين</h3>
              <p style={{ color: '#9CA3AF', fontSize: '0.875rem' }}>عرض وإدارة حسابات المستخدمين</p>
            </div>

            <div style={{ backgroundColor: '#374151', padding: '1.5rem', borderRadius: '0.5rem', textAlign: 'center' }}>
              <h3 style={{ fontSize: '1.125rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>إدارة الطلبات</h3>
              <p style={{ color: '#9CA3AF', fontSize: '0.875rem' }}>متابعة وتجهيز الطلبات</p>
            </div>

            <div style={{ backgroundColor: '#374151', padding: '1.5rem', borderRadius: '0.5rem', textAlign: 'center' }}>
              <h3 style={{ fontSize: '1.125rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>الإحصائيات</h3>
              <p style={{ color: '#9CA3AF', fontSize: '0.875rem' }}>عرض إحصائيات وتقارير الموقع</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const App = () => {
  return (
    <Router>
      <AuthProvider>
        <NavigationProvider>
          <div style={{ minHeight: '100vh', backgroundColor: '#111827', color: 'white' }}>
            <Navbar />
            <main style={{ maxWidth: '1200px', margin: '0 auto', padding: '2rem 1rem' }}>
              <Routes>
                <Route path="/" element={<Home />} />
                <Route path="/login" element={<Login />} />
                <Route path="/register" element={<Register />} />
                <Route path="/game/:id" element={<GameDetail />} />
                <Route path="/cart" element={<Cart />} />
                <Route path="/profile" element={<Profile />} />
                <Route path="/favorites" element={<Favorites />} />
                <Route path="/google/callback" element={<GoogleCallback />} />
                <Route path="/test-backend" element={<TestBackend />} />
                <Route path="/admin" element={<AdminDashboard />} />
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </main>
            <Notifications />
          </div>
        </NavigationProvider>
      </AuthProvider>
    </Router>
  );
};

export default App;
